mapper.select:
SELECT COUNT(*)::int
FROM agent_ui.conversation
WHERE id = #{id}
  AND user_id = #{userId}
  AND archived_at IS NULL

mapper.update:
UPDATE agent_ui.conversation
SET updated_at = #{updatedAt}
WHERE id = #{id}

    AND user_id = #{userId}

UPDATE agent_ui.conversation
SET title = #{title},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND title IN ('新对话', 'CLI 会话')

    AND user_id = #{userId}

UPDATE agent_ui.conversation
SET title = #{title},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND archived_at IS NULL

    AND user_id = #{userId}

UPDATE agent_ui.conversation
SET archived_at = #{archivedAt},
    updated_at = #{archivedAt}
WHERE id = #{id}
  AND archived_at IS NULL

    AND user_id = #{userId}

mapper.delete:
DELETE FROM agent_ui.conversation
WHERE id = #{id}

    AND user_id = #{userId}
